interface Item {
  type: string;
}

interface Step {
  type: string;
  items: Item[];
}

interface Scenario {
  steps: Step[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export function processScenario(scenario: Scenario): unknown {
  const items = scenario.steps[0].items;

  const basePremium = items.reduce(
    (sum, item) => sum + BASE_PREMIUM[item.type],
    0,
  );
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);

  return [{ premium }];
}

